// Mutual infinite recursion
void function_a();  // Forward declaration

void function_b() {
    function_a();  // Noncompliant: calls function_a infinitely
}

void function_a() {
    function_b();  // Noncompliant: calls function_b infinitely
}

// Missing base case condition
int fibonacci_bad(int n) {
    // Noncompliant: condition never stops recursion
    if (n > 0) {
        return fibonacci_bad(n-1) + fibonacci_bad(n-2);
    }
    return 1;  // This is never reached for n > 0
}

compliant:
// Proper recursion with base case
int factorial_good(int n) {
    if (n <= 1) {        // Compliant: base case
        return 1;
    }
    return n * factorial_good(n - 1);
}

// Iterative alternative
int factorial_iterative(int n) {
    int result = 1;
    for (int i = 2; i <= n; i++) {  // Compliant: no recursion
        result *= i;
    }
    return result;
}

// Proper Fibonacci with base cases
int fibonacci_good(int n) {
    if (n <= 0) return 0;      // Compliant: base case
    if (n == 1) return 1;      // Compliant: base case
    return fibonacci_good(n-1) + fibonacci_good(n-2);
}

// Iterative alternative
int fibonacci_iterative(int n) {
    if (n <= 0) return 0;
    if (n == 1) return 1;

    int a = 0, b = 1, temp;
    for (int i = 2; i <= n; i++) {  // Compliant: iterative
        temp = a + b;
        a = b;
        b = temp;
    }
    return b;
}

// Tail recursion with proper termination
int countdown(int n) {
    if (n <= 0) {              // Compliant: clear base case
        printf("Done!\n");
        return 0;
    }
    printf("%d\n", n);
    return countdown(n - 1);    // Compliant: guaranteed to terminate
}
